import{_ as e,o,c as t,j as a,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"Harmony","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/Harmony.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/Harmony.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/Harmony.md"};function d(l,r,h,m,c,i){return o(),t("div",null,[...r[0]||(r[0]=[a("h1",{id:"harmony",tabindex:"-1"},[n("Harmony "),a("a",{class:"header-anchor",href:"#harmony","aria-label":'Permalink to "Harmony"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),s('<h1 id="harmony-1" tabindex="-1">Harmony <a class="header-anchor" href="#harmony-1" aria-label="Permalink to &quot;Harmony&quot;">​</a></h1><p>Harmony<br> C+2000<br> 魔幻本质</p><p>武器伤害12L 高速5 基础装弹量6 射程30米<br> 为Harmony装弹的动作将上升一级<br> 这是一柄有弦和乐键的左轮手枪，它的枪管是小号的铜管，它的扳机是手摇风琴的按弦，它通体黑黄色，在风吹过时会自然发出乐音<br> Harmony造成的伤害属性均为精神伤害<br> 其在通常情况下不能附带招式进行攻击，以其进行的所有射击检定都需要标准动作才能进行攻击或至少为标准动作，下属四种曲调的效果便有一种可以应用在其中</p><p>Berceuse<br> 造成的伤害将转化为造成冲击点数，但会附带等量的耳鸣点数，使用Berceuse发射的子弹将以声波形式出现，也不会消耗其转轮内填入的子弹。当已经在某个场景内利用此效果进行攻击过时，下一次以Berceuse进行的攻击造成的冲击伤害将等量转化为对被攻击者头部造成的肢体妨碍，以标准形式豁免。</p><p>Walzer<br> 使用Walzer进行攻击时，可以从迂回步的前进与后退中选择一个，当选择前进步时，Walzer的使用者最多可以向前移动15M，当选择后退步时，被攻击者将会向后后退15M。当攻击者与被攻击者之间的距离正好在30米之间时，攻击者将视为对被攻击者有免疫C级措手不及。</p><p>Rhapsody<br> 使用Rhapsody进行攻击时，将再使自身承受2点不可豁免的亢奋点数，当Rhapsody形态发射子弹时，这颗子弹在击中第一个敌人后将开始弹跳，并接连击中该目标15米半径范围内的所有敌人，这些敌人将正常以防御抵御这发子弹造成的攻击。在亢奋点数未达严重状态前，Rhapsody的使用者每有2点亢奋点数，就可以无视1点子弹弹跳时被攻击者的掩蔽防御。</p><p>Concerto<br> 使用Concerto进行攻击时，还必须持有另一把手枪同时射击才能正常进行一次攻击。参与此次攻击的两把手枪将共用拥有的特性，武器伤害取高，攻击范围取低结算。当攻击一个濒死的角色时，可以消耗1点意志进行攻击，若其有一轮一次免疫单体攻击或每日一次及以上时间内免疫一次任意攻击的无敌，则无视；若此次攻击将其击杀，则其无法通过S级及以下的复活能力复活。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const b=e(p,[["render",d]]);export{_ as __pageData,b as default};
